import { PrismaClient } from "@prisma/client";

const prisma = new PrismaClient({
  datasources: { db: { url: process.env.DATABASE_URL } },
});

async function withRetry<T>(fn: () => Promise<T>, retries = 5, delay = 5000): Promise<T> {
  for (let i = 0; i < retries; i++) {
    try {
      return await fn();
    } catch (e: any) {
      if (i < retries - 1 && (e?.message?.includes("Can't reach database") || e?.message?.includes("connect"))) {
        console.log(`  ⏳ DB retry ${i+2}/${retries} in ${delay/1000}s...`);
        await new Promise(r => setTimeout(r, delay));
      } else throw e;
    }
  }
  throw new Error("Max retries reached");
}

type Q = {
  topic: string;
  year: number;
  questionText: string;
  optionA: string;
  optionB: string;
  optionC: string;
  optionD: string;
  correctOption: "A" | "B" | "C" | "D";
  explanation: string;
  difficulty: "EASY" | "MEDIUM" | "HARD";
};

async function seed(name: string, questions: Q[]) {
  const subject = await withRetry(() =>
    prisma.subject.findFirst({ where: { name, level: "SHS" } })
  );
  if (!subject) {
    console.log(`  WARNING: ${name} not found in database. Skipping.`);
    return;
  }

  // Use createMany in batches of 50 to reduce connection pressure
  const batchSize = 50;
  let totalCreated = 0;

  for (let i = 0; i < questions.length; i += batchSize) {
    const batch = questions.slice(i, i + batchSize);
    try {
      const result = await withRetry(() =>
        prisma.question.createMany({
          data: batch.map(q => ({
            level: "SHS",
            examType: "WASSCE" as any,
            subjectId: subject.id,
            topic: q.topic,
            year: q.year,
            questionText: q.questionText,
            optionA: q.optionA,
            optionB: q.optionB,
            optionC: q.optionC,
            optionD: q.optionD,
            correctOption: q.correctOption,
            explanation: q.explanation,
            difficulty: q.difficulty as any,
          })),
          skipDuplicates: true,
        })
      );
      totalCreated += result.count;
      console.log(`  ${name}: batch ${Math.floor(i/batchSize)+1} - ${result.count} created`);
    } catch (err: any) {
      console.log(`  ${name}: batch ${Math.floor(i/batchSize)+1} error - ${err.message.slice(0,80)}`);
    }
  }
  console.log(`  ${name}: ${totalCreated} total new questions added`);
}

